ctrl("iso-5-12","ISO 27001","Organizational Controls","A.5","A.5.12","Classification of Information","Information shall be classified according to information security needs based on confidentiality, integrity, and availability.",["Define classification levels (Public, Internal, Confidential, Restricted)","Label all information assets","Define handling procedures per level","Train employees on classification"],["Classification policy","Labeled documents","Handling procedures","Training records"],["Data exposure","Inappropriate handling","Compliance violations"],"high",{"nist_800_53":["RA-2"],"cis_v8":["3.7"]},["A.5.9","A.5.13"],["https://www.iso.org/standard/27001"]),
ctrl("iso-5-15","ISO 27001","Organizational Controls","A.5","A.5.15","Access Control","Rules to control physical and logical access to information shall be established based on business and security requirements.",["Implement role-based access","Apply least privilege","Review access quarterly","Require formal access requests"],["Access control policy","RBAC configuration","Access review records","Request/approval forms"],["Unauthorized access","Privilege creep","Data breach"],"high",{"nist_800_53":["AC-1","AC-2","AC-3"],"cis_v8":["5.1","6.1"]},["A.5.16","A.5.18","A.8.3"],["https://www.iso.org/standard/27001"]),
