if __name__=="__main__":
    print("GRC Batch 2 — ISO 27001...")
    data = {"id":"iso-27001","name":"ISO 27001:2022","description":"Information Security Management System — Annex A Controls","controls":ISO}
    path = OUTPUT_DIR / "iso_27001.json"
    with open(path,'w') as f: json.dump(data,f,indent=2)
    print(f"  ISO 27001: {len(ISO)} controls")
    total=0
    for fp in OUTPUT_DIR.glob("*.json"):
        with open(fp) as f:
            d=json.load(f)
            if isinstance(d,list): total+=len(d)
            elif "controls" in d: total+=len(d["controls"])
    print(f"\n  TOTAL CONTROLS: {total}")
